function getPrice(product, group) {
  if (!product) return 0;
  return product.prices?.[group] ?? product.prices?.PREMIUM ?? 0;
}
function genId()      { return Date.now().toString(36) + Math.random().toString(36).slice(2,5); }
function genOrderNo() {
  const n = new Date();
  return `BB-${n.getFullYear()}${String(n.getMonth()+1).padStart(2,"0")}${String(n.getDate()).padStart(2,"0")}-${Math.floor(Math.random()*9000+1000)}`;
}
function fmtDate(ts) {
  const d = new Date(ts);
  return `${d.getMonth()+1}/${d.getDate()} ${String(d.getHours()).padStart(2,"0")}:${String(d.getMinutes()).padStart(2,"0")}`;
}

// ── 수량 추출 헬퍼 ───────────────────────────────────────────────────────
// 핵심 원칙: 수량은 반드시 키워드 "이후" 텍스트에서만 찾는다.
// 키워드 앞은 "* 10kg" 처럼 단위가 명시된 경우에만 허용.
function extractQty(message, kwStart, kwEnd) {
  // ① 키워드 뒤 구간
  const after = message.substring(kwEnd, Math.min(message.length, kwEnd + 30));

  // 1순위: 바로 뒤에 숫자+단위 (공백 유무 무관)
  const m1 = after.match(/^\s*(\d+(?:\.\d+)?)\s*(?:kg|킬로그램|킬로|키로|키그|kilo)\b/i);
  if (m1) return parseFloat(m1[1]);

  // 2순위: 구분자 + 숫자 + 단위
  const m2 = after.match(/[\s,\-\/]\s*(\d+(?:\.\d+)?)\s*(?:kg|킬로그램|킬로|키로|키그|kilo)\b/i);
  if (m2) return parseFloat(m2[1]);

  // 3순위: 숫자만 — 뒤에 구분자·조사·문장끝·주문어 중 하나
  const m3 = after.match(/[\s,]?\s*(\d+(?:\.\d+)?)\s*(?:,|\n|$|이랑|하고|랑|과|을|를|은|는|개|봉|포대|박스|\s+주세요|\s+부탁|\s+원합|\s+줘|\s+보내|\s*$)/);
  if (m3) return parseFloat(m3[1]);

  // 4순위: 뒤에 아무것도 없거나 공백만 있는 숫자 (문장 끝)
  const m4 = after.match(/^\s*(\d+(?:\.\d+)?)\s*[\s,]?/);
  if (m4 && m4[1]) return parseFloat(m4[1]);

  // ② 키워드 앞 — 단위 명시된 경우만 (단가표 양식: "10kg * 가격")
  const before = message.substring(Math.max(0, kwStart - 10), kwStart);
  const m5 = before.match(/(\d+(?:\.\d+)?)\s*(?:kg|킬로그램|킬로|키로|키그|kilo)\s*\*?\s*$/i);
  if (m5) return parseFloat(m5[1]);

  return 0;
}

// ── 국가코드 → 원산지 한글명 매핑 ──────────────────────────────────────
// 문자에서 "CO 후일라", "ET 예가체프", "콜롬비아" 등을 모두 같은 원산지로 처리
const COUNTRY_MAP = {
  // 중남미
  CO: ["콜롬비아","colombia"],
  BR: ["브라질","brazil"],
  GT: ["과테말라","guatemala"],
  MX: ["멕시코","mexico"],
  SV: ["엘살바도르","el salvador","엘살"],
  HN: ["온두라스","honduras"],
  JM: ["자메이카","jamaica"],
  CR: ["코스타리카","costa rica","코스타"],
  PA: ["파나마","panama"],
  PE: ["페루","peru"],
  // 아프리카
  RW: ["르완다","rwanda"],
  ET: ["에티오피아","ethiopia"],
  YE: ["예멘","yemen"],
  UG: ["우간다","uganda"],
  KE: ["케냐","kenya"],
  TN: ["탄자니아","tanzania"],
  // 아시아
  VN: ["베트남","vietnam"],
  ID: ["인도네시아","indonesia"],
  IN: ["인도","india"],
};

// 품목의 국가코드 추론 (품목명 또는 id 앞 2자리 기준)
function inferCountryCode(product) {
  // id가 "CO-001" 같은 형태면 앞 2자
  const idCode = product.id.split("-")[0].toUpperCase();
  if (COUNTRY_MAP[idCode]) return idCode;
  // 품목명에서 국가코드 2글자로 시작하는 경우 (예: "CO 후일라 EP")
  const nameCode = product.name.substring(0,2).toUpperCase();
  if (COUNTRY_MAP[nameCode]) return nameCode;
  // origin 필드에서 국가 이름 매칭
  if (product.origin) {
    const originLower = product.origin.toLowerCase();
    for (const [code, aliases] of Object.entries(COUNTRY_MAP)) {
      if (aliases.some(a => originLower.includes(a.toLowerCase()))) return code;
    }
  }
  return null;
}

// 문자에서 특정 위치(idx)가 "원산지/국가코드" 매칭인지 확인하고
// 그 위치에 속하는 품목 후보 목록을 반환
// priceList 기반으로 동적 생성
function buildOriginIndex(priceList) {
  // { "콜롬비아" -> Set<productId>, "CO" -> Set<productId>, ... }
  const index = {};
  for (const p of priceList) {
    const code = inferCountryCode(p);
    if (!code) continue;
    const aliases = [code, ...(COUNTRY_MAP[code] || [])];
    for (const alias of aliases) {
      const key = alias.toLowerCase();
      if (!index[key]) index[key] = new Set();
      index[key].add(p.id);
    }
  }
  return index;
}

// ── 파서 상수 ─────────────────────────────────────────────────────────────
const PARSE_SKIP_WORDS = new Set([
  "et","br","co","gt","cr","hn","pa","pe","ke","tn","ug","rw","ye","vn","id","in","sv","jm","mx",
  "에티오피아","콜롬비아","브라질","케냐","파나마","코스타리카","온두라스",
  "과테말라","탄자니아","인도","인도네시아","베트남","르완다","예멘","우간다","엘살바도르","자메이카","멕시코","페루",
  "워시드","내추럴","허니","펄프드","무산소","더블","퍼멘테이션","washed","natural","honey","pulped","anaerobic",
  "마이크로랏","싱글오리진","블렌드","스위스워터","마운틴워터","시그니쳐","디카페인",
  "커피","원두","생두","주문","발주","발송","부탁","안녕","담당자",
  "드립니다","주세요","부탁드려요","입니다","합니다","드려요","이요","감사합니다",
  "금일","오늘","내일","당일","긴급","빨리",
  "kg","킬로","키로","킬로그램",
  "님","선생님",
]);

function getSegWords(seg) {
  return [...new Set(
    seg.toLowerCase().split(/[\s\/\-\+]+/)
      .filter(w => w.length >= 2 && !PARSE_SKIP_WORDS.has(w) && !/^\d+(\.\d+)?$/.test(w))
  )];
}

function getProductNameWords(p) {
  return [...new Set(
    p.name.toLowerCase().split(/[\s\/\-\[\]]+/)
      .filter(w => w.length >= 2 && !PARSE_SKIP_WORDS.has(w) && !/^\d+(\.\d+)?$/.test(w))
  )];
}

// ── 파서 ─────────────────────────────────────────────────────────────────
function parseLocally(message, priceList) {
  const items      = [];
  const ambiguous  = [];
  const matchedIds = new Set();
  // 수량 전용 줄을 이전 줄에 병합 ("5kg", "5" 등)
  const rawLines = message.split(/\n/);
  const mergedLines = [];
  for (let i = 0; i < rawLines.length; i++) {
    const line = rawLines[i].trim();
    const isQtyOnly = /^\d+(\.\d+)?\s*(kg|킬로|키로|킬로그램)?$/i.test(line) && line.length <= 8;
    if (isQtyOnly && mergedLines.length > 0) {
      mergedLines[mergedLines.length - 1] += " " + line;
    } else {
      mergedLines.push(line);
    }
  }

  // 세그먼트 분절 (줄바꿈은 이미 처리, 쉼표/이랑/하고/그리고)
  const segments = mergedLines
    .flatMap(l => l.split(/[,，]|이랑|하고|그리고/))
    .map(s => s.trim())
    .filter(s => s.length > 0);

  for (const seg of segments) {
    const segWords = getSegWords(seg);
    if (segWords.length === 0) continue;

    const scored = priceList
      .filter(p => !matchedIds.has(p.id))
      .map(p => {
        const pw = getProductNameWords(p);
        const overlap = segWords.filter(sw => pw.includes(sw));
        return { p, score: overlap.length };
      })
      .filter(s => s.score > 0)
      .sort((a, b) => b.score - a.score);

    if (scored.length === 0) continue;

    const maxScore = scored[0].score;
    const top = scored.filter(s => s.score === maxScore).map(s => s.p);

    // 수량 추출: kg/킬로 단위가 붙은 숫자 우선, 없으면 독립된 숫자(앞에 문자 없는 것)
    const qtyWithUnit = seg.match(/(?<![a-zA-Z])(\d+(?:\.\d+)?)\s*(?:kg|킬로그램|킬로|키로)\b/i);
    const qtyBare     = seg.match(/(?<![a-zA-Z\d])(\d+(?:\.\d+)?)(?!\s*[a-zA-Z])/);
    const qty = qtyWithUnit ? parseFloat(qtyWithUnit[1]) : qtyBare ? parseFloat(qtyBare[1]) : 0;

    if (top.length === 1) {
      const p = top[0];
      items.push({ product_id: p.id, product_name: p.name, quantity: qty, unit: "kg" });
      matchedIds.add(p.id);
    } else {
      ambiguous.push({
        keyword: segWords.join(" "), qty, segment: seg,
        candidates: top.map(p => ({ id: p.id, name: p.name })),
      });
    }
  }

  // 발신자 추출
  let senderName = null;
  const cafeM = message.match(/(카페|로스터리|커피)\s*([가-힣A-Za-z0-9]+)/);
  const dashM = message.match(/-\s*([^\n\-]+?)\s*$/m);
  const ipdM  = message.match(/(?:여기\s+)?([가-힣A-Za-z]{2,10})\s*(?:입니다|이에요)/);
  if (cafeM)      senderName = `${cafeM[1]} ${cafeM[2]}`.trim();
  else if (ipdM)  senderName = ipdM[1].trim();
  else if (dashM) senderName = dashM[1].trim();

  const urgent = /급|긴급|빨리|당일/i.test(message);
  const allNames = [
    ...items.map(it => `${it.product_name} ${it.quantity}kg`),
    ...ambiguous.map(a => `${a.keyword} ${a.qty > 0 ? a.qty+"kg" : "?kg"} (품목 선택 필요)`),
  ].join(", ");

  return {
    sender_name: senderName,
    summary: senderName
      ? `${senderName}에서 ${allNames || "상품"} 주문 요청.${urgent ? " 긴급." : ""}`
      : `${allNames || "주문"} 요청.${urgent ? " 긴급." : ""}`,
    intent: (items.length + ambiguous.length) > 0 ? "발주요청" : "기타",
    urgent, special_request: null, items, ambiguous,
  };
}


// ── 거래처 발송용 텍스트 생성 (복사용) ──────────────────────────────────
function buildPlainText(analysis, items, group, clientName, payMethod="account") {
  const displayName = clientName || analysis.sender_name || "";
  const totalQty   = items.reduce((s,it)=>s+it.qty,0);
  const delivFee   = totalQty < 20 ? DELIVERY_FEE : 0;
  const subtotal   = items.reduce((s,it)=>s+getPrice(it.matched,group)*it.qty,0);
  const total      = subtotal + delivFee;
  const isCard     = payMethod === "card";
  return [
    "안녕하세요.",
    "바른생각",
    "다른커피",
    "블레스빈 전진혁입니다.",
    "요청하신 단가 안내드립니다.",
    "",
    displayName,
    "",
    ...items.map(it => {
      const p=it.matched; const pr=getPrice(p,group);
      return p ? `${p.name} ${it.qty}kg * ${pr.toLocaleString()}원` : `${it.product_name} ${it.qty}kg * 확인필요`;
    }),
    "",
    ...(delivFee > 0 ? [`*배송비 ${delivFee.toLocaleString()}원`, ""] : []),
    `총 금액 ${total.toLocaleString()}원`,
    "",
    // 카드결제면 계좌번호/입금확인 제거하고 카드결제 안내 추가
    ...(!isCard ? [
      "*계좌번호 1006-901-483313 우리은행 블레스빈",
      "",
      "* 14시 전 입금시 당일출고",
      "* 입금 확인문자 부탁드립니다",
    ] : [
      "* 카드결제 - 결제링크는 추후 별도 안내드립니다.",
    ]),
  ].join("\n");
}

// ── 물류팀 오더방용 텍스트 생성 ─────────────────────────────────────────
function buildOrderText(items, group, clientName, analysis, payMethod="account") {
  const displayName = clientName || analysis.sender_name || "";
  const totalQty    = items.reduce((s,it) => s+it.qty, 0);
  const delivFee    = totalQty < 20 ? DELIVERY_FEE : 0;
  const subtotal    = items.reduce((s,it) => s+getPrice(it.matched,group)*it.qty, 0);
  const total       = subtotal + delivFee;
  const isCard      = payMethod === "card";

  return [
    displayName,
    "",
    ...items.map(it => {
      const p  = it.matched;
      const pr = getPrice(p, group);
      return p
        ? `${p.name} ${it.qty}kg * ${pr.toLocaleString()}원`
        : `${it.product_name} ${it.qty}kg * 확인필요`;
    }),
    "",
    ...(delivFee > 0 ? [`*배송비 ${delivFee.toLocaleString()}원`] : []),
    `총 금액 ${total.toLocaleString()}원`,
    // 카드결제면 마지막에 링크요청 추가
    ...(isCard ? ["", "*카드결제링크요청"] : []),
  ].join("\n");
}

// ── 복사 유틸 ─────────────────────────────────────────────────────────────
function copyToClipboard(text, onDone) {
  if (navigator.clipboard?.writeText) {
    navigator.clipboard.writeText(text).then(onDone).catch(() => fallbackCopy(text, onDone));
  } else {
    fallbackCopy(text, onDone);
  }
}
function fallbackCopy(text, onDone) {
  const el = document.createElement("textarea");
  el.value = text;
  el.style.cssText = "position:fixed;top:-9999px;opacity:0;";
  document.body.appendChild(el);
  el.focus(); el.select();
  try { document.execCommand("copy"); onDone?.(); } catch {}
  document.body.removeChild(el);
}

// ── 복사 버튼 ─────────────────────────────────────────────────────────────
function CopyBtn({ text, label="📋 문자 복사", style={} }) {
  const [done, setDone] = useState(false);
  function go() { copyToClipboard(text, () => { setDone(true); setTimeout(()=>setDone(false),2000); }); }
  return (
    <button onClick={go} style={{ padding:"5px 13px", borderRadius:8, border:"1px solid rgba(212,175,55,0.4)", background:done?"rgba(212,175,55,0.18)":"transparent", color:done?"#b8860b":"#7a6a4a", fontSize:12, cursor:"pointer", fontWeight:600, whiteSpace:"nowrap", ...style }}>
      {done ? "✓ 복사됨" : label}
    </button>
  );
}

